--

CREATE TABLE public.hr_employee_esob_records (
    id bigint NOT NULL,
    employee_id text NOT NULL,
    service_start_date date NOT NULL,
    service_end_date date NOT NULL,
    termination_mode text NOT NULL,
    include_basic_salary boolean DEFAULT true NOT NULL,
    include_other_allowance boolean DEFAULT false NOT NULL,
    include_accommodation_allowance boolean DEFAULT false NOT NULL,
    include_travel_allowance boolean DEFAULT false NOT NULL,
    include_food_allowance boolean DEFAULT false NOT NULL,
    unused_leave_days numeric(10,2) DEFAULT 0 NOT NULL,
    unused_ticket_count integer DEFAULT 0 NOT NULL,
    ticket_amount numeric(12,2) DEFAULT 0 NOT NULL,
    manual_additions numeric(12,2) DEFAULT 0 NOT NULL,
    manual_deductions numeric(12,2) DEFAULT 0 NOT NULL,
    notes text,
    print_language text DEFAULT 'bilingual'::text NOT NULL,
    calc_service_years numeric(10,2) DEFAULT 0 NOT NULL,
    calc_monthly_wage numeric(12,2) DEFAULT 0 NOT NULL,
    calc_esob_amount numeric(12,2) DEFAULT 0 NOT NULL,
    calc_leave_amount numeric(12,2) DEFAULT 0 NOT NULL,
    calc_ticket_amount numeric(12,2) DEFAULT 0 NOT NULL,
    calc_gross_amount numeric(12,2) DEFAULT 0 NOT NULL,
    calc_net_amount numeric(12,2) DEFAULT 0 NOT NULL,
    created_by uuid,
    updated_by uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    contract_type text DEFAULT 'indefinite'::text,
    termination_reason text,
    CONSTRAINT hr_employee_esob_records_amounts_chk CHECK (((ticket_amount >= (0)::numeric) AND (manual_additions >= (0)::numeric) AND (manual_deductions >= (0)::numeric) AND (calc_service_years >= (0)::numeric) AND (calc_monthly_wage >= (0)::numeric) AND (calc_esob_amount >= (0)::numeric) AND (calc_leave_amount >= (0)::numeric) AND (calc_ticket_amount >= (0)::numeric))),
    CONSTRAINT hr_employee_esob_records_dates_chk CHECK ((service_end_date >= service_start_date)),
    CONSTRAINT hr_employee_esob_records_leave_chk CHECK ((unused_leave_days >= (0)::numeric)),
    CONSTRAINT hr_employee_esob_records_mode_chk CHECK ((termination_mode = ANY (ARRAY['resignation'::text, 'non_resignation'::text]))),
    CONSTRAINT hr_employee_esob_records_print_lang_chk CHECK ((print_language = ANY (ARRAY['en'::text, 'ar'::text, 'bilingual'::text]))),
    CONSTRAINT hr_employee_esob_records_ticket_cnt_chk CHECK ((unused_ticket_count >= 0))
);


