    CONSTRAINT settlement_rules_qualification_cycle_check CHECK ((qualification_cycle_years > 0)),
    CONSTRAINT settlement_rules_qualification_cycle_unit_check CHECK ((qualification_cycle_unit = ANY (ARRAY['year'::text, 'month'::text]))),
    CONSTRAINT settlement_rules_rule_name_ar_check CHECK ((btrim(rule_name_ar) <> ''::text)),
    CONSTRAINT settlement_rules_rule_name_en_check CHECK ((btrim(rule_name_en) <> ''::text)),
    CONSTRAINT settlement_rules_rule_type_check CHECK ((rule_type = ANY (ARRAY['ticket'::text, 'leave_salary'::text]))),
    CONSTRAINT settlement_rules_ticket_count_check CHECK (((ticket_count IS NULL) OR (ticket_count > 0)))
);


